function loadRiskGrid() {
    const grid = document.getElementById('riskGrid');
    grid.innerHTML = '';
    
    mockDRPData.forEach((risk, index) => {
        const div = document.createElement('div');
        div.className = `risk-card glass ${risk.class}`;
        
        let badgeClass = 'badge-medium';
        if (risk.class === 'high') badgeClass = 'badge-high';
        if (risk.class === 'low') badgeClass = 'badge-low';
        
        div.innerHTML = `
            <div class="risk-header">
                <div>
                    <h3 style="color: #fff; margin-bottom: 4px;">${risk.hazard}</h3>
                    <p style="font-size: 0.85rem; color: var(--text-secondary);">${risk.daerah} - Mukim ${risk.mukim}</p>
                </div>
                <span class="risk-badge ${badgeClass}">Score: ${risk.risk_score}</span>
            </div>
            <p style="font-size: 0.8rem; font-weight: 600; color: var(--text-secondary); margin-bottom: 1rem;">${risk.kategori}</p>
            <button class="btn-review" data-index="${index}" style="width: 100%; padding: 0.5rem; background: rgba(255,255,255,0.1); border: 1px solid rgba(255,255,255,0.2); border-radius: 4px; color: #fff; cursor: pointer; transition: all 0.3s ease;">Review Full Profile</button>
        `;
        grid.appendChild(div);
    });
}

// Modal Logic
document.getElementById('riskGrid').addEventListener('click', function(e) {
    if (e.target.classList.contains('btn-review')) {
        const index = e.target.getAttribute('data-index');
        const risk = mockDRPData[index];
        
        document.getElementById('modalHazardTitle').innerText = risk.hazard;
        document.getElementById('modalDaerahMukim').innerText = `${risk.daerah} - Mukim ${risk.mukim}`;
        document.getElementById('modalScore').innerText = risk.risk_score;
        document.getElementById('modalCategory').innerText = risk.kategori;
        document.getElementById('modalTempat').innerText = risk.tempat || "Tiada maklumat tempat spesifik";
        
        // Color code score based on class
        const scoreEl = document.getElementById('modalScore');
        if (risk.class === 'high') scoreEl.style.color = '#ef4444';
        else if (risk.class === 'medium') scoreEl.style.color = '#f59e0b';
        else scoreEl.style.color = '#10b981';
        
        document.getElementById('profileModal').style.display = 'flex';
    }
});

document.getElementById('closeModalBtn').addEventListener('click', function() {
    document.getElementById('profileModal').style.display = 'none';
});

// Close modal when clicking outside
document.getElementById('profileModal').addEventListener('click', function(e) {
    if (e.target === this) {
        this.style.display = 'none';
    }
});

loadRiskGrid();

// Form Submission Simulation
document.getElementById('drp-form').addEventListener('submit', function(e) {
    e.preventDefault();
    
    const submitBtn = document.getElementById('submitBtn');
    const msg = document.getElementById('submitMessage');
    
    submitBtn.innerText = 'Syncing to DRP Database...';
    submitBtn.style.opacity = '0.7';
    
    setTimeout(() => {
        submitBtn.innerText = 'Update DRP Database';
        submitBtn.style.opacity = '1';
        
        msg.innerText = '✅ DRP Database successfully updated!';
        msg.style.color = '#10b981';
        
        this.reset();
        setTimeout(() => { msg.innerText = ''; }, 5000);
    }, 1500);
});
